import sys
from collections import defaultdict

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    parent = [i for i in range(c + 1)]
    rank = [1] * (c + 1)
    online = [True] * (c + 1)
    online_sets = defaultdict(set)

    for i in range(1, c + 1):
        online_sets[i].add(i)

    def find(u: int) -> int:
        while parent[u] != u:
            parent[u] = parent[parent[u]]
            u = parent[u]
        return u

    def union(u: int, v: int):
        u_root = find(u)
        v_root = find(v)
        if u_root == v_root:
            return
        if rank[u_root] > rank[v_root]:
            parent[v_root] = u_root
            online_sets[u_root].update(online_sets[v_root])
            online_sets[v_root].clear()
        else:
            parent[u_root] = v_root
            online_sets[v_root].update(online_sets[u_root])
            online_sets[u_root].clear()
            if rank[u_root] == rank[v_root]:
                rank[v_root] += 1

    for u, v in connections:
        union(u, v)

    result = []
    for query in queries:
        type_q, x = query
        if type_q == 1:
            if online[x]:
                result.append(x)
            else:
                root = find(x)
                if not online_sets[root]:
                    result.append(-1)
                else:
                    result.append(min(online_sets[root]))
        elif type_q == 2:
            if online[x]:
                online[x] = False
                root = find(x)
                online_sets[root].remove(x)

    return result
