using namespace std;

class UnionFind {
private:
    vector<long long> parent;
    vector<long long> size;
    vector<set<long long>> onlineSets;

public:
    UnionFind(long long n) {
        parent.resize(n + 1);
        size.resize(n + 1, 1);
        onlineSets.resize(n + 1);
        for (long long i = 1; i <= n; ++i) {
            parent[i] = i;
            onlineSets[i].insert(i);
        }
    }

    long long find(long long x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unionSets(long long x, long long y) {
        long long rootX = find(x);
        long long rootY = find(y);
        if (rootX == rootY) return;

        if (size[rootX] < size[rootY]) {
            swap(rootX, rootY);
        }
        parent[rootY] = rootX;
        size[rootX] += size[rootY];
        onlineSets[rootX].insert(onlineSets[rootY].begin(), onlineSets[rootY].end());
        onlineSets[rootY].clear();
    }

    set<long long>& getOnlineSet(long long x) {
        return onlineSets[find(x)];
    }
};

vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    UnionFind uf(c);
    vector<bool> online(c + 1, true);

    for (const auto& conn : connections) {
        uf.unionSets(conn[0], conn[1]);
    }

    vector<long long> result;
    for (const auto& query : queries) {
        long long type = query[0];
        long long x = query[1];
        if (type == 1) {
            if (online[x]) {
                result.push_back(x);
            } else {
                auto& onlineSet = uf.getOnlineSet(x);
                if (onlineSet.empty()) {
                    result.push_back(-1);
                } else {
                    result.push_back(*onlineSet.begin());
                }
            }
        } else if (type == 2) {
            if (online[x]) {
                online[x] = false;
                long long root = uf.find(x);
                uf.getOnlineSet(root).erase(x);
            }
        }
    }
    return result;
}

